import{_ as t,o,c as r,ad as a}from"./chunks/framework.DdcUsuRQ.js";const p=JSON.parse('{"title":"Derived roles","description":"Parametric expansion of one role into a family. derivedFrom names the parent, hueOffset rotates around the OKLCH hue wheel.","frontmatter":{"title":"Derived roles","description":"Parametric expansion of one role into a family. derivedFrom names the parent, hueOffset rotates around the OKLCH hue wheel.","head":[["link",{"rel":"canonical","href":"https://studnicky.github.io/iridis/reference/role-schema/derived-from"}],["meta",{"property":"og:url","content":"https://studnicky.github.io/iridis/reference/role-schema/derived-from"}],["meta",{"property":"og:title","content":"Derived roles: iridis"}],["meta",{"property":"og:description","content":"Parametric expansion of one role into a family. derivedFrom names the parent, hueOffset rotates around the OKLCH hue wheel."}],["meta",{"name":"twitter:title","content":"Derived roles: iridis"}],["meta",{"name":"twitter:description","content":"Parametric expansion of one role into a family. derivedFrom names the parent, hueOffset rotates around the OKLCH hue wheel."}],["meta",{"name":"description","content":"Parametric expansion of one role into a family. derivedFrom names the parent, hueOffset rotates around the OKLCH hue wheel."}],["meta",{"property":"article:modified_time","content":"2026-05-17T16:04:29.000Z"}],["meta",{"property":"article:author","content":"Andrew Studnicky"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"BreadcrumbList\\",\\"itemListElement\\":[{\\"@type\\":\\"ListItem\\",\\"position\\":1,\\"name\\":\\"iridis\\",\\"item\\":\\"https://studnicky.github.io/iridis/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":2,\\"name\\":\\"Reference\\",\\"item\\":\\"https://studnicky.github.io/iridis/reference\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":3,\\"name\\":\\"Role Schema\\",\\"item\\":\\"https://studnicky.github.io/iridis/reference/role-schema\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":4,\\"name\\":\\"Derived roles\\",\\"item\\":\\"https://studnicky.github.io/iridis/reference/role-schema/derived-from\\"}]}"]]},"headers":[],"relativePath":"reference/role-schema/derived-from.md","filePath":"reference/role-schema/derived-from.md","lastUpdated":1779033869000}'),i={name:"reference/role-schema/derived-from.md"};function d(s,e,n,h,c,l){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="derived-roles" tabindex="-1">Derived roles <a class="header-anchor" href="#derived-roles" aria-label="Permalink to &quot;Derived roles&quot;">​</a></h1><p>A role with <code>derivedFrom: &#39;other-role-name&#39;</code> declares itself as a parametric <strong>child</strong> of another role. The engine&#39;s <code>expand:family</code> task fills the derived role from the parent&#39;s resolved value, with optional <code>hueOffset</code> to rotate around the OKLCH hue wheel.</p><h2 id="shape" tabindex="-1">Shape <a class="header-anchor" href="#shape" aria-label="Permalink to &quot;Shape&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Meaning</th></tr></thead><tbody><tr><td><code>derivedFrom</code></td><td><code>string</code></td><td>Name of the parent role (must exist in <code>roles[]</code>).</td></tr><tr><td><code>hueOffset</code></td><td><code>number</code></td><td>Degrees to rotate the parent&#39;s hue. Positive = clockwise on the OKLCH hue ring.</td></tr></tbody></table><h2 id="what-it-does" tabindex="-1">What it does <a class="header-anchor" href="#what-it-does" aria-label="Permalink to &quot;What it does&quot;">​</a></h2><p><code>expand:family</code> runs after <code>resolve:roles</code> and before <code>enforce:contrast</code>. For each role with <code>derivedFrom</code>:</p><ol><li>Look up the parent&#39;s resolved OKLCH coordinates.</li><li>Copy <code>L</code> and <code>C</code> (clamped to the child&#39;s own <code>lightnessRange</code> / <code>chromaRange</code>).</li><li>Rotate the parent&#39;s <code>h</code> by <code>hueOffset</code> (mod 360).</li><li>Reconstruct the child&#39;s RGB / hex from the rotated OKLCH.</li></ol><p>The child inherits the parent&#39;s lightness and chroma; only hue differs. This is what makes a single brand seed produce an entire syntax-token family: <code>syntax-string</code> is <code>brand</code> shifted +120°, <code>syntax-number</code> is <code>brand</code> shifted +60°, etc.</p><h2 id="what-it-means" tabindex="-1">What it means <a class="header-anchor" href="#what-it-means" aria-label="Permalink to &quot;What it means&quot;">​</a></h2><p>Derivation encodes <strong>family relationships</strong>. A schema with <code>text-strong</code> derived from <code>text</code> says &quot;text-strong is the strong tier of text, it lives where text lives, just shifted&quot;. A schema with <code>syntax-keyword</code> derived from <code>brand</code> says &quot;all syntax tokens orbit the brand colour&quot;.</p><p>The engine guarantees that if the parent moves (because the user picked a different seed), every child moves with it on the same hue arc. Designers author the relationship <em>once</em> in the schema, and every palette the user produces preserves it.</p><h2 id="how-to-author" tabindex="-1">How to author <a class="header-anchor" href="#how-to-author" aria-label="Permalink to &quot;How to author&quot;">​</a></h2><ul><li>Use <code>derivedFrom</code> whenever the child&#39;s identity depends on the parent&#39;s. Brand-derived syntax tokens, status-derived signal colours, text-derived emphasis tiers.</li><li>Pair <code>derivedFrom</code> with <code>lightnessRange</code> / <code>chromaRange</code> envelopes that the inherited <code>L</code> / <code>C</code> will land inside. The inherited values are clamped, so a too-narrow range will collapse the derivation back toward grey.</li><li>Pick <code>hueOffset</code> values that produce <strong>perceptually distinct</strong> results. Multiples of 30° (<code>30</code>, <code>60</code>, <code>90</code>, <code>120</code>, <code>150</code>, <code>180</code>, ...) keep the family ring-like.</li><li>Don&#39;t chain derivations more than two levels deep. <code>expand:family</code> is a single pass; a grandchild that derives from a child only sees the child&#39;s pre-expansion state, which is unusual but well-defined.</li></ul><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./hue-lock">Hue lock</a>: opposite knob, pin a role&#39;s hue regardless of seed.</li><li><a href="./lightness-range">Lightness range</a> and <a href="./chroma-range">Chroma range</a>: the envelopes the inherited values are clamped into.</li><li><a href="./../../concepts/role-schemas">Role schemas overview</a>.</li></ul>',15)])])}const u=t(i,[["render",d]]);export{p as __pageData,u as default};
